struct DSU {
    parent: Vec<usize>,
    rank: Vec<usize>,
    count: usize,
}

impl DSU {
    fn new(n: usize) -> Self {
        let parent: Vec<usize> = (0..n).collect();
        let rank: Vec<usize> = vec![1; n];
        DSU { parent, rank, count: n }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) {
        let x_root = self.find(x);
        let y_root = self.find(y);
        if x_root == y_root {
            return;
        }
        if self.rank[x_root] < self.rank[y_root] {
            self.parent[x_root] = y_root;
        } else {
            self.parent[y_root] = x_root;
            if self.rank[x_root] == self.rank[y_root] {
                self.rank[x_root] += 1;
            }
        }
        self.count -= 1;
    }

    fn get_count(&self) -> usize {
        self.count
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    if edges.is_empty() {
        return 0;
    }
    let mut edges_sorted = edges;
    edges_sorted.sort_by(|a, b| a[2].cmp(&b[2]));
    let max_time = edges_sorted.iter().map(|e| e[2]).max().unwrap();
    let mut low = 0;
    let mut high = max_time;
    let mut ans = max_time;
    while low <= high {
        let mid = (low + high) / 2;
        let mut dsu = DSU::new(n as usize);
        for edge in &edges_sorted {
            let time = edge[2];
            if time > mid {
                let u = edge[0] as usize;
                let v = edge[1] as usize;
                dsu.union(u, v);
            }
        }
        let cnt = dsu.get_count();
        if cnt >= k {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    ans
}
